esqlQuery.esql:
FROM metrics-traefik.otel-*
// Limit to TLS cert expiry timestamps (Unix epoch seconds)
| WHERE traefik_tls_certs_not_after IS NOT NULL
// Take latest expiry per cert (cn + serial)
| STATS expiry_epoch = MAX(traefik_tls_certs_not_after) BY attributes.cn, attributes.serial
// Convert epoch seconds to datetime; compute days until expiry
// Adjust 30-day threshold based on renewal lead time
| EVAL expiry_datetime = TO_DATETIME(expiry_epoch * 1000)
| EVAL days_until_expiry = DATE_DIFF("days", NOW(), expiry_datetime)
| WHERE days_until_expiry < 30 AND days_until_expiry >= 0
| SORT days_until_expiry ASC
